import{_ as r}from"./Menu.bf643b41.js";import{u}from"./composables.a20be60a.js";import{r as e,a as n,e as a,b as o,f as i,o as c}from"./entry.b2c8d4ee.js";const d=""+new URL("article-audit-ux.63d54140.jpg",import.meta.url).href,p={class:"banniere"},m=i('<div class="margium-l marge-haute-l"><div class="espacium"><div class="colonnes"><div class="colonne"><h1>L&#39;audit UX</h1><div class="projettitre"></div> 20 janvier 2023 \xB7 3 min </div><div class="colonne"></div></div></div></div>',1),b=i('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p> Pour \xE9valuer l&#39;utilisabilit\xE9 d&#39;un dispositif, il existe 2 m\xE9thodes : le test utilisateur et l&#39;audit UX.<br> Cette derni\xE8re repose sur des crit\xE8res scientifiques appel\xE9s Heuristiques. Elle permet de d\xE9busquer les probl\xE8mes que peuvent rencontrer les utilisateurs et de proposer des solutions. L&#39;Audit UX est souvent utilis\xE9 pour \xE9tablir des &quot;Quick Fix&quot;, des points d&#39;am\xE9liorations faciles sur une interface pour obtenir de meilleurs taux de conversions. C&#39;est \xE9galement une mani\xE8re de v\xE9rifier une conception avant sa production. </p><h2>Les diff\xE9rentes approches Heuristiques</h2><p>Pour \xE9valuer une interface ou un dispositif, il existe une dizaine d&#39;approches d\u2019heuristiques diff\xE9rente, ici, nous allons voir les plus communes et les plus repr\xE9sentatives de leurs positionnements</p><ul><li><b>Bastien et Scapin</b>, sont sans aucun doute les Heuristiques les plus utilis\xE9es, car elles r\xE9pondent au besoin g\xE9n\xE9ral d\u2019\xE9valuation de <b>l&#39;utilisabilit\xE9</b>. Elles visent \xE0 r\xE9pondre \xE0 la probl\xE9matique suivante : \xC0 quel point il est ais\xE9 d&#39;accomplir des t\xE2ches simples pour un utilisateur qui d\xE9couvre l&#39;application. </li><li><b>Colombo &amp; Pasch&#39;s</b> Quant \xE0 elle, se focalise sur l&#39;\xE9valuation de <b>l\u2019efficacit\xE9</b> d&#39;un dispositif. Une fois que les utilisateurs ont appris le design, avec quelle efficacit\xE9 ils peuvent effectuer une t\xE2che. Cette approche peut \xEAtre utilis\xE9e dans les applications m\xE9tier.</li><li><b>Arhippainen&#39;s</b> Vise a \xE9valu\xE9 davantage la <b>satisfaction</b>, s&#39;il est plaisant d&#39;utiliser le dispositif et s&#39;il est engageant. Il peut \xEAtre utilis\xE9 dans les probl\xE9matiques de divertissement et de gamification </li></ul><h2>Les Heuristiques de Bastien et Scapin</h2><ul><li><b>Guidage</b><ul><li><b>Regroupement et s\xE9paration</b> Est-ce que les \xE9l\xE9ments qui se ressemblent sont regroup\xE9s et s\xE9par\xE9s des autres ? (Les \xE9l\xE9ments de navigation sont s\xE9par\xE9s du contenu de la page, les fraises sont dans la rubrique fruits, les VTT ne sont pas avec les v\xE9los de ville, etc) </li><li> Est-ce que l&#39;interface fait des <b>retours utilisateur</b> imm\xE9diat (message d&#39;erreur, de succ\xE8s, annonce un temps de chargement, etc.) </li><li><b>Lisibilit\xE9</b> (est-ce que le fil d\u2019Ariane et visible, est-ce que les textes sont suffisamment grands et contrast\xE9s pour \xEAtre lu, etc.) </li><li><b>Incitant</b> (est-ce que les intitul\xE9s sont clairs sur ce qu&#39;ils regroupent, est-ce que les noms des boutons et les ic\xF4nes sont explicites) </li></ul></li><li><b>Charge de travail</b><ul><li><b>Bri\xE8vet\xE9</b> \xCAtre bref sur le nombre d&#39;actions \xE0 accomplir pour arriver \xE0 un objectif (limiter le nombre de champs et d\u2019informations demand\xE9es pour cr\xE9er un compte ou passer une commande) </li><li><b>Concision</b> Transmettre l&#39;information avec un nombre limit\xE9 de mots </li><li><b>Densit\xE9 de l&#39;information</b>, Avoir une mise en page et une structuration minimaliste pour permettre \xE0 l&#39;utilisateur de scanner rapidement la page et de trouver les \xE9l\xE9ments qu&#39;il l\u2019int\xE9resse </li></ul></li><li><b>Contr\xF4le explicite</b><ul><li><b>Expliciter les actions de l&#39;utilisateur</b>, l&#39;interface doit traiter les actions que lui demandent l&#39;utilisateur et ceux seulement lorsqu&#39;il le demande. </li><li><b>Contr\xF4le utilisateur</b>, L&#39;utilisateur doit avoir le contr\xF4le du syst\xE8me : annuler une action, mettre en pause, fermer une modale, etc. </li></ul></li><li><b>Adaptabilit\xE9</b><ul><li><b>Flexibilit\xE9</b> S&#39;adapter aux usages des utilisateurs (terminaux mobile et bureau, mode de navigation divers, contextes d&#39;usages, etc.) </li><li><b>Exp\xE9rience utilisateurs</b> L&#39;interface doit s&#39;adapter aux diff\xE9rents niveaux de ma\xEEtrise des utilisateurs : fournir des raccourcis pour les utilisateurs exp\xE9riment\xE9s, une FAQ, tutoriel ou une guidance explicite pour les utilisateurs novices, etc. </li></ul></li><li><b>Gestion des erreurs</b><ul><li><b>Pr\xE9ventions des erreurs</b>, limiter les erreurs en explicitant en amont les exigences du syst\xE8me : ex mentionner et compter les nombres de caract\xE8res requis pour cr\xE9er un mot de passe, donner la taille max et le format pour l&#39;envoi d&#39;un fichier. </li><li><b>Qualit\xE9 des messages d&#39;erreurs</b> Le syst\xE8me fournit-il un message d&#39;erreur clair et pr\xE9cis qui permette facilement \xE0 l\u2019utilisateur de la r\xE9soudre ? </li><li><b>Correction des erreurs</b> Le syst\xE8me, sugg\xE8re-t-il les corrections des erreurs ? ex : lors d&#39;une recherche avec un mot mal orthographi\xE9, affiche une page 404 avec une possibilit\xE9 de continuer sa navigation ? </li></ul></li><li><b>Homog\xE9n\xE9it\xE9 &amp; Coh\xE9rence</b> Les interfaces pr\xE9sentent les \xE9l\xE9ments et le nommage de ces derniers de mani\xE8re constante dans l&#39;int\xE9gralit\xE9 de l&#39;application ? </li><li><b>Signifiance des codes et d\xE9nominations</b> Est-ce que la s\xE9mantique des ic\xF4nes et des couleurs sont repr\xE9sentatifs de ce qu&#39;ils symbolisent ? ex : un message de succ\xE8s est affich\xE9 en vert, l&#39;icon loupe et utilis\xE9 pour effectuer une recherche etc.</li><li><b>Compatibilit\xE9</b> L&#39;application prend elle en compte les capacit\xE9s des utilisateurs pour effectuer une t\xE2che, pour \xE9viter \xE0 l&#39;utilisateur des charges cognitives sup\xE9rieur : s&#39;assurer d&#39;utiliser son r\xE9f\xE9rentiel plut\xF4t qu&#39;utiliser des termes dont il va devoir trouver la d\xE9finition, utiliser les m\xEAmes syst\xE8mes de mesures, de calendrier, langues, etc. </li></ul><h2>Restitution et forme de l&#39;audit</h2><p>Un audit est un livrable, il est n\xE9cessaire qu&#39;il soit clair, structur\xE9, concis, complet, d\xE9coupable et orient\xE9 solutions pour pouvoir \xEAtre trait\xE9 facilement par les \xE9quipes de design et de d\xE9veloppement.</p><img src="'+d+'" loading="lazy" alt="Exemple de pr\xE9sentation d&#39;audit UX"></div></div></article>',1),_={__name:"audit-ux",setup(f){const s=e("L'audit UX - Lucas Lacroix"),t=e("Pour \xE9valuer l'utilisabilit\xE9 d'un dispositif, il existe 2 m\xE9thodes : le test utilisateur et l'audit UX. Cette derni\xE8re repose sur des crit\xE8res scientifiques appel\xE9s Heuristiques. Elle permet de d\xE9busquer les probl\xE8mes que peuvent rencontrer les utilisateurs");return u({title:s,meta:[{name:"description",content:t}]}),(v,g)=>{const l=r;return c(),n("div",null,[a("div",p,[o(l),m]),b])}}};export{_ as default};
